function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by their removal time
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find (Disjoint Set Union) data structure
    const parent: number[] = Array(n).fill(0).map((_, i) => i);
    const rank: number[] = Array(n).fill(0);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) return false;
        if (rank[rootU] > rank[rootV]) {
            parent[rootV] = rootU;
        } else if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
        } else {
            parent[rootV] = rootU;
            rank[rootU]++;
        }
        return true;
    }

    // We will use a binary search approach on the time
    let left = 0;
    let right = 10**9;
    let result = 10**9;

    // We need to find the smallest time t such that after removing all edges with time <= t,
    // the number of connected components is at least k
    // So we can perform a binary search on the time

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);

        // Reset the DSU for each binary search step
        parent.forEach((_, i) => parent[i] = i);
        rank.fill(0);

        // Process all edges with time <= mid
        for (const [u, v, time] of edges) {
            if (time <= mid) {
                union(u, v);
            }
        }

        // Count the number of connected components
        const components = new Set<number>();
        for (let i = 0; i < n; i++) {
            components.add(find(i));
        }

        if (components.size >= k) {
            // We can try to find a smaller time
            result = mid;
            right = mid - 1;
        } else {
            // Need to remove more edges
            left = mid + 1;
        }
    }

    return result;
}

